 32	int decode_pdn_disconnect_reject(pdn_disconnect_reject_msg *pdn_disconnect_reject, uint8_t *buffer, uint32_t len)
 33	{
 34	  uint32_t decoded = 0;
 35	  int decoded_result = 0;
 36	
 37	  // Check if we got a NULL pointer and if buffer length is >= minimum length expected for the message.
 38	  CHECK_PDU_POINTER_AND_LENGTH_DECODER(buffer, PDN_DISCONNECT_REJECT_MINIMUM_LENGTH, len);
 39	
 40	  /* Decoding mandatory fields */
 41	  if ((decoded_result = decode_esm_cause(&pdn_disconnect_reject->esmcause, 0, buffer + decoded, len - decoded)) < 0)
 42	    return decoded_result;
 43	  else
 44	    decoded += decoded_result;
 45	
 46	  /* Decoding optional fields */
 47	  while(len - decoded > 0) {
 48	    uint8_t ieiDecoded = *(buffer + decoded);
 49	
 50	    /* Type | value iei are below 0x80 so just return the first 4 bits */
 51	    if (ieiDecoded >= 0x80)
 52	      ieiDecoded = ieiDecoded & 0xf0;
 53	
 54	    switch(ieiDecoded) {
 55	    case PDN_DISCONNECT_REJECT_PROTOCOL_CONFIGURATION_OPTIONS_IEI:
 56	      if ((decoded_result =
 57	             decode_protocol_configuration_options(&pdn_disconnect_reject->protocolconfigurationoptions,
 58	                 PDN_DISCONNECT_REJECT_PROTOCOL_CONFIGURATION_OPTIONS_IEI,
 59	                 buffer + decoded, len - decoded)) <= 0)
 60	        return decoded_result;
 61	
 62	      decoded += decoded_result;
 63	      /* Set corresponding mask to 1 in presencemask */
 64	      pdn_disconnect_reject->presencemask |= PDN_DISCONNECT_REJECT_PROTOCOL_CONFIGURATION_OPTIONS_PRESENT;
 65	      break;
 66	
 67	    default:
 68	      errorCodeDecoder = TLV_DECODE_UNEXPECTED_IEI;
 69	      return TLV_DECODE_UNEXPECTED_IEI;
 70	    }
 71	  }
 72	
 73	  return decoded;
 74	}
