 76	int encode_pdn_disconnect_reject(pdn_disconnect_reject_msg *pdn_disconnect_reject, uint8_t *buffer, uint32_t len)
 77	{
 78	  int encoded = 0;
 79	  int encode_result = 0;
 80	
 81	  /* Checking IEI and pointer */
 82	  CHECK_PDU_POINTER_AND_LENGTH_ENCODER(buffer, PDN_DISCONNECT_REJECT_MINIMUM_LENGTH, len);
 83	
 84	  if ((encode_result = encode_esm_cause(&pdn_disconnect_reject->esmcause, 0,
 85	                                        buffer + encoded, len - encoded)) < 0)        //Return in case of error
 86	    return encode_result;
 87	  else
 88	    encoded += encode_result;
 89	
 90	  if ((pdn_disconnect_reject->presencemask & PDN_DISCONNECT_REJECT_PROTOCOL_CONFIGURATION_OPTIONS_PRESENT)
 91	      == PDN_DISCONNECT_REJECT_PROTOCOL_CONFIGURATION_OPTIONS_PRESENT) {
 92	    if ((encode_result =
 93	           encode_protocol_configuration_options(&pdn_disconnect_reject->protocolconfigurationoptions,
 94	               PDN_DISCONNECT_REJECT_PROTOCOL_CONFIGURATION_OPTIONS_IEI, buffer +
 95	               encoded, len - encoded)) < 0)
 96	      // Return in case of error
 97	      return encode_result;
 98	    else
 99	      encoded += encode_result;
100	  }
101	
102	  return encoded;
103	}
